#!/bin/bash
# =============================================================================
# PostgreSQL HA - 镜像导入脚本
# =============================================================================

echo "========================================="
echo " PostgreSQL HA - 离线镜像导入"
echo "========================================="

if [ ! -f "postgres-ha-v1.0.tar" ]; then
    echo "[错误] 找不到镜像包 postgres-ha-v1.0.tar，请确保它与本脚本在同一目录下！"
    exit 1
fi

echo "[信息] 开始导入 Docker 镜像，这可能需要几十秒钟，请稍候..."
docker load -i postgres-ha-v1.0.tar

if [ $? -eq 0 ]; then
    echo "[成功] 镜像导入完成！"
    echo "请确认已经正确修改了 .env 文件中的 IP 配置，然后执行 ./start.sh 启动节点。"
else
    echo "[错误] 镜像导入失败，请检查 Docker 服务是否正在运行。"
    exit 1
fi
